func newAuthCmd(flags *rootFlags) *cobra.Command {
	cmd := &cobra.Command{
		Use:   "auth",
		Short: "Manage authentication for Google Search Console",
	}

	cmd.AddCommand(newAuthStatusCmd(flags))
	cmd.AddCommand(newAuthSetTokenCmd(flags))
	cmd.AddCommand(newAuthSetClientCmd(flags))
	cmd.AddCommand(newAuthLoginCmd(flags))
	cmd.AddCommand(newAuthLogoutCmd(flags))
	cmd.AddCommand(newAuthForgetCmd(flags))

	return cmd
}

func newAuthStatusCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:     "status",
		Short:   "Show authentication status",
		Example: "  google-search-console-pp-cli auth status",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			w := cmd.OutOrStdout()
			header := cfg.AuthHeader()
			authed := header != ""

			// PATCH(oauth-login): richer status. JSON envelope now includes
			// refresh-token presence, expiry (RFC3339 + relative), client_id
			// presence, and which precedence layer is active. Token values
			// themselves are never echoed.
			expiryStr := ""
			expiresIn := ""
			if !cfg.TokenExpiry.IsZero() {
				expiryStr = cfg.TokenExpiry.Format(time.RFC3339)
				d := time.Until(cfg.TokenExpiry).Round(time.Second)
				if d < 0 {
					expiresIn = "expired"
				} else {
					expiresIn = "in " + d.String()
				}
			}

			if flags.asJSON {
				out := map[string]any{
					"authenticated":       authed,
					"source":              cfg.AuthSource,
					"config":              cfg.Path,
					"has_client":          cfg.HasClient(),
					"has_refresh_token":   cfg.RefreshToken != "",
					"access_token_expiry": expiryStr,
					"expires_in":          expiresIn,
				}
				if printErr := printJSONFiltered(w, out, flags); printErr != nil {
					return printErr
				}
				if !authed {
					return authErr(fmt.Errorf("no credentials configured"))
				}
				return nil
			}
			if !authed {
				fmt.Fprintln(w, red("Not authenticated"))
				fmt.Fprintln(w, "")
				fmt.Fprintln(w, "Recommended (interactive, auto-refreshes):")
				fmt.Fprintln(w, "  google-search-console-pp-cli auth set-client <client_id> <client_secret>")
				fmt.Fprintln(w, "  google-search-console-pp-cli auth login")
				fmt.Fprintln(w, "")
				fmt.Fprintln(w, "For CI / one-shot scripts:")
				fmt.Fprintln(w, "  export GSC_ACCESS_TOKEN=\"your-token-here\"")
				return authErr(fmt.Errorf("no credentials configured"))
			}

			fmt.Fprintln(w, green("Authenticated"))
			fmt.Fprintf(w, "  Source:           %s\n", cfg.AuthSource)
			fmt.Fprintf(w, "  Config:           %s\n", cfg.Path)
			fmt.Fprintf(w, "  OAuth client:     %s\n", boolYesNo(cfg.HasClient()))
			fmt.Fprintf(w, "  Refresh token:    %s\n", boolYesNo(cfg.RefreshToken != ""))
			if expiryStr != "" {
				fmt.Fprintf(w, "  Token expiry:     %s (%s)\n", expiryStr, expiresIn)
			}
			if cfg.AuthSource == "env:GSC_ACCESS_TOKEN" && cfg.RefreshToken == "" {
				fmt.Fprintln(w, "")
				fmt.Fprintln(w, yellow("Note: GSC_ACCESS_TOKEN is set but there's no refresh token, so the next call will fail when this token expires."))
				fmt.Fprintln(w, "      Run 'auth login' for auto-refresh.")
			}
			return nil
		},
	}
}

func newAuthSetTokenCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:     "set-token <token>",
		Short:   "Save an API access token to the config file (no auto-refresh — prefer 'auth login')",
		Example: "  google-search-console-pp-cli auth set-token YOUR_TOKEN_HERE",
		Args:    cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			// Clear any legacy auth_header so AuthHeader() falls through to
			// the newly-saved credential. Without this, a pre-existing
			// auth_header value (common after regenerate) shadows the saved
			// token and set-token silently has no effect.
			cfg.AuthHeaderVal = ""
			// PATCH(oauth-login): clear RefreshToken and TokenExpiry so the auto-refresh
			// gate in client.authHeader() does not silently swap the just-pasted token
			// for one obtained via the stale refresh token. Keep ClientID/ClientSecret
			// so a later "auth login" does not require a re-"set-client".
			if err := cfg.SaveTokens(cfg.ClientID, cfg.ClientSecret, args[0], "", time.Time{}); err != nil {
				return configErr(fmt.Errorf("saving token: %w", err))
			}

			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
					"saved":       true,
					"config_path": cfg.Path,
				}, flags)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "Token saved to %s\n", cfg.Path)
			fmt.Fprintln(cmd.OutOrStdout(), yellow("Note: set-token does not enable auto-refresh. Prefer 'auth login' if you have an OAuth client configured."))
			return nil
		},
	}
}

// PATCH(oauth-login): set-client persists OAuth client credentials so 'auth
// login' knows which app to authenticate against. Separate from set-token
// because tokens are short-lived but client credentials are long-lived.
func newAuthSetClientCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "set-client <client_id> <client_secret>",
		Short: "Save Google OAuth client credentials (one-time setup before 'auth login')",
		Long: `Save the OAuth client_id and client_secret from your Google Cloud Console.

This is a one-time setup step. After saving, run 'auth login' to authenticate.
Credentials are persisted to the config file (mode 0600).

Get credentials:
  1. Google Cloud Console -> APIs & Services -> Credentials
  2. Create Credentials -> OAuth client ID -> Application type: Desktop app
  3. Copy the Client ID and Client secret

Per Google's docs, the "client secret" of a Desktop OAuth client is not truly
secret — it's an identifier. Treat it as low-sensitivity but don't paste into
shared logs.`,
		Example: "  google-search-console-pp-cli auth set-client 1234.apps.googleusercontent.com GOCSPX-abc123",
		Args:    cobra.ExactArgs(2),
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}
			if err := cfg.SaveClient(args[0], args[1]); err != nil {
				return configErr(fmt.Errorf("saving client: %w", err))
			}
			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
					"saved":       true,
					"config_path": cfg.Path,
				}, flags)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "OAuth client saved to %s\n", cfg.Path)
			fmt.Fprintln(cmd.OutOrStdout(), "")
			fmt.Fprintln(cmd.OutOrStdout(), "Next: run 'auth login' to sign in.")
			return nil
		},
	}
}

func newAuthLogoutCmd(flags *rootFlags) *cobra.Command {
	var revoke bool
	cmd := &cobra.Command{
		Use:     "logout",
		Short:   "Clear stored tokens (keeps OAuth client — use 'auth forget' to nuke everything)",
		Example: "  google-search-console-pp-cli auth logout\n  google-search-console-pp-cli auth logout --revoke",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			// PATCH(oauth-login): --revoke calls Google's revocation endpoint
			// so the token is invalidated server-side before we delete it.
			// Default is local-only (matches gh/gcloud convention) because
			// users mostly want to switch accounts, not invalidate the grant.
			revoked := false
			if revoke && cfg.RefreshToken != "" {
				if err := revokeAtGoogle(cmd.Context(), cfg.RefreshToken); err != nil {
					fmt.Fprintf(cmd.OutOrStdout(), "Warning: revoke at Google failed: %v\n", err)
				} else {
					revoked = true
				}
			}

			if err := cfg.ClearTokens(); err != nil {
				return configErr(fmt.Errorf("clearing tokens: %w", err))
			}

			envStillSet := ""
			if os.Getenv("GSC_ACCESS_TOKEN") != "" {
				envStillSet = "GSC_ACCESS_TOKEN"
			}

			if flags.asJSON {
				out := map[string]any{
					"cleared": true,
					"revoked": revoked,
				}
				if envStillSet != "" {
					out["note"] = envStillSet + " env var is still set"
				}
				return printJSONFiltered(cmd.OutOrStdout(), out, flags)
			}

			if envStillSet != "" {
				fmt.Fprintf(cmd.OutOrStdout(), "Config cleared. Note: %s env var is still set.\n", envStillSet)
				return nil
			}
			if revoked {
				fmt.Fprintln(cmd.OutOrStdout(), "Logged out. Refresh token revoked at Google.")
			} else {
				fmt.Fprintln(cmd.OutOrStdout(), "Logged out. Credentials cleared (OAuth client kept — run 'auth login' to sign back in).")
			}
			return nil
		},
	}
	cmd.Flags().BoolVar(&revoke, "revoke", false, "Also revoke the refresh token at Google (default: local-only)")
	return cmd
}

// PATCH(oauth-login): forget nukes everything. For users switching to a
// different Google Cloud project, or fully resetting auth state.
func newAuthForgetCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:     "forget",
		Short:   "Clear ALL auth state (tokens + OAuth client)",
		Example: "  google-search-console-pp-cli auth forget",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}
			if err := cfg.ForgetAll(); err != nil {
				return configErr(fmt.Errorf("forget: %w", err))
			}
			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
					"forgotten":   true,
					"config_path": cfg.Path,
				}, flags)
			}
			fmt.Fprintln(cmd.OutOrStdout(), "Forgot everything. Run 'auth set-client' + 'auth login' to start over.")
			return nil
		},
	}
}

// boolYesNo renders a bool as a human-readable "yes"/"no". Status fields
// read more naturally as a flat list of words than as colored markers when
// the underlying value is binary.
func boolYesNo(b bool) string {
	if b {
		return "yes"
	}
	return "no"
}
